import{_ as e,c as t,o as l,a4 as a}from"./chunks/framework.HaEZziQ1.js";const h=JSON.parse('{"title":"gulp","description":"","frontmatter":{},"headers":[],"relativePath":"Document/Project-Engineering/前端工具链/gulp.md","filePath":"Document/Project-Engineering/前端工具链/gulp.md","lastUpdated":null}'),r={name:"Document/Project-Engineering/前端工具链/gulp.md"},n=a('<h1 id="gulp" tabindex="-1">gulp <a class="header-anchor" href="#gulp" aria-label="Permalink to &quot;gulp&quot;">​</a></h1><p>官网：<a href="https://www.gulpjs.com.cn/" target="_blank" rel="noreferrer">https://www.gulpjs.com.cn/</a></p><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>gulp 是一个基于流的自动化构建工具。</p><p>除了可以管理和执行任务，还支持监听文件、读写文件。基于内存实现的，其构建速度比 Grunt 快，而且，Gulp 的生态也很完善，插件质量很高。目前最为流行。</p><p>它不仅能对⽹站资源进⾏优化，⽽且在开发过程中很多重复的任务能够使用正确的⼯具⾃动完成 Gulp 的核⼼概念：流</p><ul><li>流，简单来说就是建⽴在⾯向对象基础上的一种抽象的处理数据的⼯具。在流中，定义了一些处理数据的基本操作，如读取数据，写⼊数据等，程序员是对流进⾏所有操作的，⽽不用关⼼流的另一头数据的真正流向</li><li>gulp 正是通过流和代码优于配置的策略来尽量简化任务编写的⼯作</li></ul><p>Gulp 的特点：</p><ul><li>易于使用：通过代码优于配置的策略，gulp 让简单的任务简单，复杂的任务可管理</li><li>构建快速 利用 Node.js 流的威⼒，你可以快速构建项⽬并减少频繁的 IO 操作</li><li>易于学习 通过最少的 API ，掌握 gulp 毫不费⼒，构建⼯作尽在掌握：如同一系列流管道</li></ul>',9),p=[n];function o(i,u,c,s,_,g){return l(),t("div",null,p)}const m=e(r,[["render",o]]);export{h as __pageData,m as default};
